// 카테고리별 항목 수 집계(tags + autoTags 합집합 기준, 항목당 카테고리 중복은 1회만). 칩 개수 배지용.
function categoryCounts(items) {
  const counts = {};
  for (const it of items || []) {
    const seen = new Set();
    for (const t of (it.tags || []).concat(it.autoTags || [])) {
      if (seen.has(t)) continue;
      seen.add(t);
      counts[t] = (counts[t] || 0) + 1;
    }
  }
  return counts;
}

