(async () => {
  location.hash = 'skills';
  // 매트릭스 로드 대기 (rows가 채워질 때까지 최대 6초)
  const wait = (ms)=>new Promise(r=>setTimeout(r,ms));
  let rows=0;
  for (let i=0;i<30;i++){
    await wait(200);
    rows = document.querySelectorAll('#skill-mx-rows tr').length;
    const skel = document.querySelector('#skill-mx-rows .skel');
    if (rows>0 && !skel) break;
  }
  // 매트릭스 raw 데이터 상태 요약
  const m = await fetch('/matrix?kind=skill').then(r=>r.json());
  const counts = m.counts;
  const total = (m.rows||[]).length;
  // scope별 분포
  const byScope = {};
  for (const r of m.rows||[]) byScope[r.scope] = (byScope[r.scope]||0)+1;
  return JSON.stringify({renderedRows:rows, totalRows: total, counts, scopes: Object.keys(byScope), byScopeSample: byScope});
})()

(async () => {
