input.expression:
(async () => {
  const wait = (ms)=>new Promise(r=>setTimeout(r,ms));
  location.hash='store';
  for (let i=0;i<30;i++){ await wait(200); if (document.querySelector('#store-list .card') || document.querySelector('#store-list .empty-state')) break; }
  const out = {};
  // 스토어 필터바에 미정 칩이 있는지
  out.storeUntaggedPill = !!document.querySelector('#store-filters .untagged-pill');
  // 스토어 카드에 미정 칩(tags 없는 항목)이 있으면 표시 — 존재 여부만
  out.storeCards = document.querySelectorAll('#store-list .card').length;
  out.storeUntaggedChips = document.querySelectorAll('#store-list .tok-chip.untagged').length;
  return JSON.stringify(out);
})()
